using System.Collections.Generic;using System.IO;namespace OpennLayer.Infrastructure.Versioning{public static class TiaVersionDetector{public static List<string> GetInstalledVersions(){var list=new List<string>();string basePath=@"C:\Program Files\Siemens\Automation\Portal";if(!Directory.Exists(basePath))return list;foreach(var dir in Directory.GetDirectories(basePath)){var name=Path.GetFileName(dir);if(name=="V19"||name=="V20"||name=="V21")list.Add(name.Replace("V",""));}return list;}}}